noncompliant:
app.UseCors(builder =>
{
    builder.AllowAnyOrigin() // Noncompliant: allows all origins
           .AllowAnyMethod()
           .AllowAnyHeader();
});

[EnableCors("*")] // Noncompliant: wildcard policy
public class MyController : Controller
{
}

compliant:
app.UseCors(builder =>
{
    builder.WithOrigins("https://trusted-site.com") // Compliant: specific origin
           .WithMethods("GET", "POST")
           .WithHeaders("Content-Type");
});

[EnableCors("TrustedOrigins")] // Compliant: named policy with specific origins
public class MyController : Controller
{
}
